from typing import Optional
from datetime import datetime

class User:
    def __init__(self, id: int, name: str, email: str) -> None:
        self.id = id
        self.name = name
        self.email = email

    def __repr__(self) -> str:
        return f"User({self.id}, {self.name!r})"

# Database mock
_users: dict[int, User] = {
    1: User(1, "Alice", "alice@example.com"),
    2: User(2, "Bob", "bob@example.com"),
}

def find_user(user_id: int) -> Optional[User]:
    """Return a User if found, None otherwise."""
    return _users.get(user_id)

# ─── Pattern 1: if/else ───────────────────────────────────────────────────────
user = find_user(1)
if user is not None:
    # Type narrowed to User here
    print(f"Found: {user.name}")  # .name is safe
else:
    print("User not found")

# ─── Pattern 2: early return ──────────────────────────────────────────────────
def get_user_email(user_id: int) -> str:
    user = find_user(user_id)
    if user is None:
        return "unknown@example.com"
    # user: User (narrowed) for the rest of the function
    return user.email

# ─── Pattern 3: raise on None ────────────────────────────────────────────────
def get_user_or_raise(user_id: int) -> User:
    user = find_user(user_id)
    if user is None:
        raise ValueError(f"User {user_id} not found")
    # user: User (narrowed by the raise above)
    return user

# ─── Pattern 4: walrus operator (Python 3.8+) ────────────────────────────────
if (found := find_user(2)) is not None:
    # found: User
    print(f"Walrus found: {found.email}")

# ─── Pattern 5: default via or ───────────────────────────────────────────────
def get_user_name(user_id: int) -> str:
    user = find_user(user_id)
    return user.name if user is not None else "Anonymous"

# ─── Pattern 6: chained Optional ─────────────────────────────────────────────
def get_user_since(user_id: int) -> Optional[datetime]:
    """Return account creation date if user has it set."""
    # Not in our model, but demonstrates chaining
    user = find_user(user_id)
    if user is None:
        return None
    # User found but creation_date might also be absent in a richer model
    return datetime(2024, 1, 1)  # placeholder

result = get_user_since(1)
if result is not None:
    print(f"Member since: {result.year}")

from typing import TypedDict, Optional, Literal
import json

# ─── Type the OpenAI tool-call response structure ────────────────────────────

class ToolCallFunction(TypedDict):
    name: str
    arguments: str  # JSON string — parse with json.loads()

class ToolCall(TypedDict):
    id: str
    type: Literal["function"]  # always "function" for function calls
    function: ToolCallFunction

class Message(TypedDict):
    role: Literal["user", "assistant", "system", "tool"]
    content: Optional[str]
    tool_calls: NotRequired[list[ToolCall]]  # only present for assistant with tool calls
    tool_call_id: NotRequired[str]           # only present for tool result messages
    name: NotRequired[str]                   # optional display name

class Choice(TypedDict):
    index: int
    message: Message
    finish_reason: Literal["stop", "tool_calls", "length", "content_filter"]

class CompletionResponse(TypedDict):
    id: str
    model: str
    choices: list[Choice]
    usage: dict[str, int]

# Import NotRequired
from typing import NotRequired

# ─── Tool dispatcher using TypedDict-typed response ──────────────────────────

def search_web(query: str) -> str:
    return f"Results for: {query}"

def calculate(expression: str) -> str:
    try:
        result = eval(expression, {"__builtins__": {}})
        return str(result)
    except Exception as e:
        return f"Error: {e}"

TOOLS = {"search_web": search_web, "calculate": calculate}

def handle_tool_calls(response: CompletionResponse) -> list[dict]:
    """Process tool calls from a typed CompletionResponse."""
    results = []
    for choice in response["choices"]:
        msg = choice["message"]
        if choice["finish_reason"] != "tool_calls":
            continue
        # tool_calls may be absent (NotRequired)
        tool_calls = msg.get("tool_calls")
        if not tool_calls:
            continue
        for tc in tool_calls:
            fn_name = tc["function"]["name"]
            fn_args = json.loads(tc["function"]["arguments"])
            if fn_name in TOOLS:
                result = TOOLS[fn_name](**fn_args)
                results.append({
                    "tool_call_id": tc["id"],
                    "role": "tool",
                    "content": result,
                })
    return results

# Example response (would come from OpenAI API)
mock_response: CompletionResponse = {
    "id": "chatcmpl-abc123",
    "model": "gpt-4",
    "choices": [{
        "index": 0,
        "message": {
            "role": "assistant",
            "content": None,
            "tool_calls": [{
                "id": "call_xyz",
                "type": "function",
                "function": {
                    "name": "calculate",
                    "arguments": '{"expression": "2 ** 10"}',
                },
            }],
        },
        "finish_reason": "tool_calls",
    }],
    "usage": {"prompt_tokens": 50, "completion_tokens": 10, "total_tokens": 60},
}

tool_results = handle_tool_calls(mock_response)
for r in tool_results:
    print(f"Tool {r['tool_call_id']}: {r['content']}")  # "1024"

from typing import Optional, Union
import time

# Optional with None check (common approach)
def process_optional(value: Optional[str]) -> str:
    if value is None:
        return "default"
    return value.upper()

# Sentinel pattern for performance-critical code
class _Sentinel:
    _instance = None
    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance

MISSING = _Sentinel()
MissingType = type(MISSING)

def process_sentinel(value: Union[str, MissingType]) -> str:
    if value is MISSING:
        return "default"
    # No isinstance needed — mypy narrows to str
    return value.upper()  # type: ignore[union-attr]

# Benchmark
n = 1_000_000
t1 = time.perf_counter()
for _ in range(n):
    process_optional("hello")
t2 = time.perf_counter()
for _ in range(n):
    process_sentinel("hello")
t3 = time.perf_counter()

print(f"Optional: {t2-t1:.3f}s")
print(f"Sentinel: {t3-t2:.3f}s")
# Difference is negligible in practice; use Optional unless profiling shows otherwise
